scwin.gr_retrieve_onafteredit = function (rowIndex, columnIndex, value) {
  let colid = gr_retrieve.getColumnID(columnIndex);
  switch (colid) {
    case "crryinoutDtm":
      value = $c.str.rpad($p, value, 14, "0");
      ds_retrieve.setCellData(rowIndex, "crryinoutDtm", value);
      break;
    case "crryinoutPatternCd":
      if (value == "23") {
        ds_retrieve.setCellData(rowIndex, "autoOutYn", "1");
        gr_retrieve.setReadOnly("cell", rowIndex, "autoOutHsn", false);
      } else {
        ds_retrieve.setCellData(rowIndex, "autoOutYn", "0");
        gr_retrieve.setReadOnly("cell", rowIndex, "autoOutHsn", true);
      }
      break;
    case "crryinoutCnt":
    case "crryinoutWt":
    case "crryinAccdCnt":
    case "crryinAccdWt":
      if ($c.util.isEmpty($p, value) || isNaN(value)) {
        ds_retrieve.setCellData(rowIndex, colid, "0");
      }
      break;
  }
};

//세관재고 프린트
scwin.btn_print_onclick = async function (e) {
  let chkwrkplcd = ed_wrkPlCd.getValue();
  if ($c.gus.cfIsNull($p, chkwrkplcd)) {
    await $c.win.alert($p, "작업장 코드는 필수 입력 항목입니다.");
    ed_wrkPlCd.focus();
    return;
  }

  // 필수항목 체크
  if (!(await $c.gus.cfValidate($p, [tb_queryList], null, true))) {
    return;
  }
  let reportFile = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_16r.ozr";
  let odiName = "op_302_01_16r";
  let mode = "";
  let odiParam = {
    "wrkPlCd": ed_wrkPlCd.getValue().trim(),
    "fromDt": crryinoutDtmFrom.getValue().trim(),
    "toDt": crryinoutDtmTo.getValue().trim()
  };
  if (chb_previewCheck1.getValue() == "1") {
    mode = "preview";
  } else if (chb_printCheck1.getValue() == "1") {
    mode = "print";
  }
  let data = {
    odiName: odiName,
    reportName: reportFile,
    odiParam: odiParam,
    viewerParam: {
      "useprogressbar": true,
      // 프로그레스바 쓸지 말지
      "mode": mode
    },
    formParam: {}
  };
  if (chb_previewCheck1.getValue() == "1") {
    // 미리보기 체크된 경우
    let opts = {
      id: "ozReportPopup",
      popupName: "오즈 리포트",
      modal: false,
      type: "browserPopup",
      width: 1000,
      height: 830,
      title: "오즈 리포트"
    };
    $c.win.openPopup($p, "/ui/cm/zz/ozreportPopup.xml", opts, data);
  } else if (chb_printCheck1.getValue() == "1") {
    // 인쇄옵션 체크된 경우
    let opts = {
      type: 'print',
      // viewer, print, download
      printMode: 'view' // silent, view
    };
    $c.ext.printOzReport($p, data, opts);
  } else {
    // 저장후바로출력
    let opts = {
      filename: odiName,
      exportMode: 'view'
    };
    $c.ext.downloadOzReport($p, data, opts);
  }
};
